import { IMessageComposer } from '@nitrots/nitro-renderer';

export class EditGangRoleComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(
        roleId: number,
        name: string,
        bankAccess: boolean,
        kickMembers: boolean,
        inviteMembers: boolean,
        administrator: boolean
    ) {
        this._data = [
            roleId,
            name,
            bankAccess,
            kickMembers,
            inviteMembers,
            administrator,
        ];
    }

    public getMessageArray(): any[] {
        console.log('Sending EditGangRoleComposer with data:', this._data);
        return this._data;
    }

    public dispose(): void {}
}
